import { useNavigate } from "react-router-dom"
export type Botao = {
    nome: string;
    action: () => void;
}
export const PageHomeUsuario = () => {
    const navigation = useNavigate()
    const botoes: Botao[] = [
        { nome: "Agendar", action: () => { navigation("/novoAgendamento") } },
        { nome: "Meus Agendamentos", action: () => { navigation("usuario/agendamento") } },
    ]
    return (
        <div style={{ display: "flex", justifyContent: "center", alignItems: "center", flexDirection: "column" }}>
       <img src={"public/images/public/images/LOGO Marca mumi braids.jpeg"}/>
            {botoes.map((botao) => (
                <div
                    style={
                        {
                            display: "flex",
                            //border: "1px solid black",                           
                          //  cursor: "pointer",

                        }
                    }
                >
                    <button onClick={botao.action}
                        style={
                            {
                                width: "200px",
                                margin: "10px",
                                padding: "10px",
                                textAlign: "center",
                                backgroundColor: "black",
                                color: "#8a2be2",
                                fontWeight: "bold",
                                borderRadius: 5,
                                fontSize: 16,
                            }
                        }
                    >
                        {botao.nome}

                    </button>
                </div>
            ))}

        </div>
    )
}
